{
  "executive_summary": "For a small team building a reliable notification system with relaxed latency requirements, Option B (event-driven with a managed queue) is the stronger choice — but only if the queue is a managed service (SQS, Cloud Tasks, or similar), not self-hosted infrastructure. Option A (synchronous REST) is simpler to start but fundamentally couples delivery tracking to notification dispatch, making retries, new channels, and failure isolation painful as the system grows. The 5-minute latency tolerance is the key architectural signal: it unlocks asynchronous processing, which directly enables the retry reliability requirement without complicating the delivery service.",

  "architecture": {
    "components": [
      { "name": "Delivery Service", "responsibility": "Tracks package delivery lifecycle, emits domain events on status changes (picked_up, in_transit, out_for_delivery, delivered, failed_attempt)", "boundaries": "Owns delivery state. Does NOT know about notification channels, templates, or customer contact preferences." },
      { "name": "Event Queue", "responsibility": "Durable buffer between delivery events and notification dispatch. Provides at-least-once delivery with visibility timeout and dead-letter queue.", "boundaries": "Managed service (e.g., AWS SQS, GCP Cloud Tasks). No custom broker infrastructure." },
      { "name": "Notification Worker", "responsibility": "Consumes delivery events, resolves customer preferences (channel, language, opt-outs), renders templates, dispatches to channel adapters, handles per-channel retries.", "boundaries": "Owns notification logic. Does not mutate delivery state." },
      { "name": "Channel Adapters", "responsibility": "Thin wrappers around external provider APIs (SendGrid, Twilio, etc.). Normalize responses into success/transient-failure/permanent-failure.", "boundaries": "One adapter per channel. Adapters are stateless and independently deployable." },
      { "name": "Notification Log", "responsibility": "Records every dispatch attempt and outcome for auditability and debugging.", "boundaries": "Append-only store. Can be a simple database table." }
    ],
    "interfaces": [
      { "from": "Delivery Service", "to": "Event Queue", "contract": "Publishes DeliveryStatusChanged event: {delivery_id, status, timestamp, customer_id}", "coupling_type": "loose — fire-and-forget publish" },
      { "from": "Event Queue", "to": "Notification Worker", "contract": "At-least-once delivery with configurable visibility timeout and dead-letter queue after N failures", "coupling_type": "loose — queue-mediated" },
      { "from": "Notification Worker", "to": "Channel Adapters", "contract": "send(recipient, message): Result<Success, TransientError, PermanentError>", "coupling_type": "loose — strategy pattern behind a common interface" },
      { "from": "Notification Worker", "to": "Notification Log", "contract": "Writes attempt records: {notification_id, channel, status, error, timestamp}", "coupling_type": "tight — direct write dependency, acceptable for logging" }
    ],
    "data_flow": "1. Delivery Service updates delivery status → 2. Publishes DeliveryStatusChanged to queue → 3. Notification Worker polls/receives event → 4. Worker resolves customer preferences and renders message → 5. Worker calls appropriate Channel Adapter(s) → 6. Adapter calls external provider → 7. Worker logs result → 8. On transient failure: message returns to queue with backoff. On repeated failure: message moves to dead-letter queue for manual inspection.",
    "patterns_used": [
      { "pattern": "Event-Driven Architecture (Option B)", "rationale": "The 5-minute latency tolerance explicitly permits async processing. This decouples the delivery service from notification concerns entirely, meaning a Twilio outage cannot slow down or break delivery tracking. The queue provides natural retry semantics — failed messages reappear after a visibility timeout — which directly addresses the 'never silently drop' reliability requirement without custom retry code in the delivery service." },
      { "pattern": "Strategy Pattern for Channel Adapters", "rationale": "New channels (push, WhatsApp) are added by implementing a new adapter behind the same interface. The worker selects adapters based on customer preferences. Zero changes to the delivery service or queue infrastructure." },
      { "pattern": "Dead-Letter Queue", "rationale": "Messages that fail all retries land in a DLQ rather than being dropped. This satisfies the high-reliability requirement by ensuring no notification is silently lost — even permanent failures are captured for human review." },
      { "pattern": "Outbox Pattern (if using a database)", "rationale": "If the delivery service uses a relational database, the outbox pattern ensures that the status update and the event publication are atomically consistent — the event is written to an outbox table in the same transaction as the status change, then a poller or CDC process publishes to the queue. This prevents the failure mode where the status updates but the event is lost." }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      { "name": "Delivery Tracking", "classification": "core", "aggregates": ["Delivery (root: delivery_id, tracks status lifecycle)"] },
      { "name": "Notification", "classification": "supporting", "aggregates": ["NotificationRequest (root: notification_id, tracks dispatch attempts per channel)", "CustomerPreferences (contact info, channel opt-ins, language)"] }
    ],
    "context_map": [
      { "upstream": "Delivery Tracking", "downstream": "Notification", "relationship": "Customer-Supplier via domain events. Delivery Tracking publishes events; Notification consumes them. Notification has no influence on the event schema — it conforms to what Delivery Tracking publishes." }
    ]
  },

  "trade_offs": [
    {
      "decision": "Option B (event-driven) over Option A (synchronous REST)",
      "gains": "Fault isolation (provider outage doesn't break delivery service), natural retry via queue redelivery, trivial channel extensibility, delivery service stays focused on its core domain",
      "sacrifices": "Slightly more moving parts (queue + worker), eventual consistency (notification is not instant — but spec allows 5 minutes), requires understanding of at-least-once semantics and idempotency",
      "alternatives_considered": ["Option A: Synchronous REST — simpler initial setup but creates tight coupling, requires custom retry logic inside the delivery service, and any new channel means modifying the delivery service codebase"]
    },
    {
      "decision": "Managed queue service over self-hosted broker (Kafka, RabbitMQ)",
      "gains": "Zero operational burden for a 3-person team — no broker patching, no disk management, no cluster rebalancing. SQS/Cloud Tasks are effectively zero-ops.",
      "sacrifices": "Vendor lock-in to cloud provider, less flexibility in routing topology compared to RabbitMQ exchanges or Kafka topics",
      "alternatives_considered": ["Self-hosted RabbitMQ — powerful but requires operational expertise the team doesn't have", "Self-hosted Kafka — massive overkill for notification volumes at a courier company scale"]
    },
    {
      "decision": "Single Notification Worker process over per-channel microservices",
      "gains": "One deployable unit for the notification context — simpler for 3 engineers to reason about, deploy, and debug. Channel selection is a code path, not a service boundary.",
      "sacrifices": "A bug in one channel adapter could affect others if not properly isolated in code. Scaling is coarse-grained (scale the whole worker, not per-channel).",
      "alternatives_considered": ["Per-channel microservices — provides blast-radius isolation but multiplies deployment, monitoring, and debugging burden beyond what a 3-person team should take on"]
    }
  ],

  "flexibility_points": [
    { "area": "Channel Adapters", "evolution_path": "Adding push notifications or WhatsApp requires implementing a new adapter (< 200 lines) and registering it. No changes to queue, delivery service, or worker orchestration logic." },
    { "area": "Customer Preferences", "evolution_path": "Currently can be a simple database table. Can evolve to support per-event-type preferences (e.g., SMS for delivery, email for delay) without architectural changes." },
    { "area": "Queue Provider", "evolution_path": "The worker consumes messages through a thin abstraction. Swapping SQS for Cloud Tasks or even a self-hosted broker later requires only changing the consumer implementation." },
    { "area": "Notification Templates", "evolution_path": "Template rendering is isolated in the worker. Can start with hardcoded templates and evolve to a template engine or CMS-driven templates without touching the delivery service." }
  ],

  "rigidity_points": [
    { "area": "Event Schema (DeliveryStatusChanged)", "reason": "This is the contract between Delivery Tracking and Notification contexts. Changes here require coordinating both sides. This rigidity is intentional — the event schema should be stable and versioned." },
    { "area": "At-Least-Once Delivery Semantics", "reason": "The system assumes idempotent notification processing. This is a foundational constraint — all channel adapters and the notification log must handle duplicate events gracefully (e.g., deduplication by delivery_id + status + channel)." },
    { "area": "Channel Adapter Interface", "reason": "The send() → Result<Success, TransientError, PermanentError> contract is intentionally rigid. All adapters must classify failures into these categories for the retry logic to work correctly." }
  ],

  "risks": [
    { "risk": "Duplicate notifications sent due to at-least-once queue semantics", "severity": "medium", "mitigation": "Idempotency key per notification (hash of delivery_id + status + channel). Check notification log before dispatching. Customers receiving a duplicate SMS is annoying but not catastrophic." },
    { "risk": "Outbox pattern skipped, leading to lost events when delivery service crashes between DB commit and queue publish", "severity": "high", "mitigation": "Implement the transactional outbox from day one. It is a simple table + poller — not complex infrastructure. Skipping it creates a subtle data loss bug that is hard to detect." },
    { "risk": "Dead-letter queue fills up without anyone noticing", "severity": "high", "mitigation": "Set up a CloudWatch/monitoring alarm on DLQ depth > 0. This is a 10-minute configuration task but critical for the 'never silently drop' requirement." },
    { "risk": "Team unfamiliar with async patterns leads to debugging difficulty", "severity": "medium", "mitigation": "Invest in structured logging with correlation IDs (delivery_id as trace key). The notification log table serves as a queryable audit trail. Keep the worker as a single process to simplify debugging." },
    { "risk": "Option A regression risk: if synchronous approach is chosen, adding retry logic and new channels will gradually turn the delivery service into a god object", "severity": "high", "mitigation": "This is the primary reason to prefer Option B. Option A's simplicity is front-loaded — the complexity debt compounds with every new channel and every provider outage." }
  ],

