    "files_to_create_or_modify": [
      "src/delivery/events.ts — DeliveryStatusChanged event definition",
      "src/delivery/outbox.ts — Outbox table writer + poller",
      "src/notifications/worker.ts — Event consumer, preference resolver, dispatch orchestrator",
      "src/notifications/adapters/email.ts — Email channel adapter (e.g., SendGrid)",
      "src/notifications/adapters/sms.ts — SMS channel adapter (e.g., Twilio)",
      "src/notifications/adapters/types.ts — Channel adapter interface and result types",
      "src/notifications/log.ts — Notification log writer + idempotency check",
      "infrastructure/queue.tf or CDK stack — SQS queue + DLQ configuration"
    ],
    "patterns_to_follow": "Strategy pattern for channel adapters. Transactional outbox for reliable event publishing. Idempotent consumers with deduplication. Structured logging with delivery_id as correlation key throughout.",
    "pitfalls_to_avoid": [
      "Do NOT start with Option A thinking you'll migrate later — the coupling becomes load-bearing quickly and migration requires rewriting the delivery service",
      "Do NOT self-host a message broker — SQS/Cloud Tasks cost pennies and require zero ops",
      "Do NOT skip the outbox pattern — 'publish after commit' is a data loss bug hiding in plain sight",
      "Do NOT build per-channel microservices — a single worker with adapter pattern gives you channel isolation without deployment complexity",
      "Do NOT forget DLQ monitoring — an unmonitored DLQ is equivalent to silently dropping notifications"
    ]
  },

  "escalations": [
    {
      "type": "architectural_ambiguity",
      "description": "The recommendation assumes a managed cloud queue service is available and acceptable. If the team is on-premise or has constraints against cloud-managed services, the architecture changes significantly — a self-hosted alternative (e.g., PostgreSQL-backed job queue like Graphile Worker or pg-boss) would be recommended instead, which changes operational characteristics.",
      "routed_to": "Coach K",
      "options": ["Managed cloud queue (SQS/Cloud Tasks) — zero ops, pay-per-use", "PostgreSQL-backed job queue (pg-boss/Graphile) — no new infrastructure if already using Postgres, but less battle-tested at scale", "Self-hosted RabbitMQ — maximum flexibility but operational burden inappropriate for 3-person team"],
      "recommendation": "Managed cloud queue if possible; Postgres-backed queue as fallback if cloud services are constrained"
    }
  ],

  "confidence": {
    "level": 60,
    "high_confidence_areas": [
      "Option B is architecturally superior to Option A for this requirements profile — the latency tolerance and reliability requirement strongly favor async",
      "Strategy pattern for channel extensibility is the right abstraction",
      "Single worker over per-channel microservices for a 3-person team",
      "Transactional outbox is necessary for reliable event publishing"
    ],
    "low_confidence_areas": [
      "Specific queue technology choice depends on team's cloud provider and infrastructure constraints (escalated)",
      "Whether the team has async/event-driven experience — if not, the learning curve could offset Option B's architectural benefits in the short term"
    ],
    "assumptions": [
      "Team has access to a managed cloud queue service or is willing to adopt one",
      "Notification volume is moderate (thousands/day, not millions) — appropriate for a courier company",
      "The delivery service already exists or is being built concurrently",
      "Customer contact information and preferences are accessible to the notification context"
    ]
  }
}

